import{_ as a,o as e,c as l,a2 as i}from"./chunks/framework.Cr-Z7ngm.js";const m=JSON.parse('{"title":"ATM与柜台支票","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"deposit/atm-and-counter-cheque.md","filePath":"zh-CN/deposit/atm-and-counter-cheque.md"}'),o={name:"deposit/atm-and-counter-cheque.md"};function r(d,t,n,s,h,c){return e(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="atm与柜台支票" tabindex="-1">ATM与柜台支票 <a class="header-anchor" href="#atm与柜台支票" aria-label="Permalink to &quot;ATM与柜台支票&quot;">​</a></h1><p>通过香港银行 ATM、银行柜台或支票将资金转账至长桥收款账户，转账完成后需上传汇款凭证。</p><table tabindex="0"><thead><tr><th>项目</th><th>说明</th></tr></thead><tbody><tr><td>支持币种</td><td>港元（HKD）、美元（USD）</td></tr><tr><td>到账时间</td><td>ATM/柜台同行转账：2 小时内；ATM/柜台跨行转账：1–3 个工作日；支票：约 2 个工作日</td></tr><tr><td>手续费</td><td>长桥免费，具体费用以银行实际收取为准</td></tr></tbody></table><h2 id="收款银行信息" tabindex="-1">收款银行信息 <a class="header-anchor" href="#收款银行信息" aria-label="Permalink to &quot;收款银行信息&quot;">​</a></h2><ul><li>收款人名称：Long Bridge HK Limited</li><li>港元收款账号：01287520564946</li><li>美元收款账号：01287520564962</li><li>收款银行：中国银行（香港）有限公司（银行编号：012）</li><li>SWIFT 代码：BKCHHKHHXXX</li><li>银行地址：2A Des Voeux Road Central, Hong Kong</li></ul><h2 id="方式一-atm-柜台转账" tabindex="-1">方式一：ATM / 柜台转账 <a class="header-anchor" href="#方式一-atm-柜台转账" aria-label="Permalink to &quot;方式一：ATM / 柜台转账&quot;">​</a></h2><ol><li>获取长桥收款账户信息（见上方）</li><li>前往香港银行 ATM 或柜台，将资金转账至长桥收款账户</li><li>保留汇款凭证截图（ATM 打印凭条或柜台回执）</li><li>打开长桥 App，进入<strong>资产 → 存入资金 → 选择币种 → ATM / 柜台转账</strong>，上传汇款凭证</li></ol><blockquote><p>完成转账后请立即上传凭证，否则影响入金进度。</p></blockquote><h2 id="方式二-支票转账" tabindex="-1">方式二：支票转账 <a class="header-anchor" href="#方式二-支票转账" aria-label="Permalink to &quot;方式二：支票转账&quot;">​</a></h2><ol><li>填写支票：正面收款人填写 <strong>Long Bridge HK Limited</strong>；反面填写<strong>长桥综合账户 + 你的账户号码</strong>（如「长桥综合账户（H10057829）」），并拍摄正反面照片</li><li>将支票递交至银行柜台或存支票机，保留转账凭证截图</li><li>打开长桥 App，进入<strong>资产 → 存入资金 → 支票转账</strong>，上传支票正面、反面截图和转账凭证</li></ol><blockquote><p>完成后请立即上传所有凭证，否则影响入金进度。</p></blockquote><h2 id="支票类型与同名账户限制" tabindex="-1">支票类型与同名账户限制 <a class="header-anchor" href="#支票类型与同名账户限制" aria-label="Permalink to &quot;支票类型与同名账户限制&quot;">​</a></h2><ul><li>仅适用于香港银行柜台及 ATM</li><li>不建议支票转至工银亚洲收款账户（核对资料需额外时间）</li><li>仅支持香港银行支票，不支持香港银行本票</li><li>转账银行账户名必须与证券账户名同名，不可使用他人账户</li><li>香港公众假期不处理汇款业务，请预留时间</li><li>不接受直接存入现金</li></ul>',13)])])}const p=a(o,[["render",r]]);export{m as __pageData,p as default};
